1	/**
2	 * Insights engine — bottleneck detection, cost estimation, parallelism gaps, stuck signals.
3	 */
4	
5	import type { Agent, State, ToolCall } from "./models.js";
6	import { createHash } from "node:crypto";
7	
8	// ── Pricing constants (per million tokens) ────────────────────────────────
9	// Sonnet 4.5
10	export const SONNET_INPUT = 3;
11	export const SONNET_OUTPUT = 15;
12	// Opus 4.7
13	export const OPUS_INPUT = 15;
14	export const OPUS_OUTPUT = 75;
15	
16	// ── Bottleneck ────────────────────────────────────────────────────────────
17	
18	export interface BottleneckResult {
19	  longestAgent: Agent | null;
20	  highestErrorAgent: Agent | null;
21	  longestDurationMs: number;
22	  highestErrorCount: number;
23	}
24	
25	export function bottleneck(state: State): BottleneckResult {
26	  let longestAgent: Agent | null = null;
27	  let longestDurationMs = 0;
28	  let highestErrorAgent: Agent | null = null;
29	  let highestErrorCount = 0;
30	
31	  for (const agent of state.agents.values()) {
32	    const duration = agent.last_seen_ms - agent.first_seen_ms;
33	    if (duration > longestDurationMs) {
34	      longestDurationMs = duration;
35	      longestAgent = agent;
36	    }
37	    if (agent.error_count > highestErrorCount) {
38	      highestErrorCount = agent.error_count;
39	      highestErrorAgent = agent;
40	    }
41	  }
42	
43	  return { longestAgent, highestErrorAgent, longestDurationMs, highestErrorCount };
44	}
45	
46	// ── Cost estimation ───────────────────────────────────────────────────────
47	
48	export interface AgentCost {
49	  agentId: string;
50	  agentName: string;
51	  inputTokens: number;
52	  outputTokens: number;
53	  usd: number;
54	  model: "sonnet" | "opus";
55	}
56	
57	export interface CostEstimateResult {
58	  perAgent: AgentCost[];
59	  totalUsd: number;
60	}
61	
62	export interface AgentCostWithSource extends AgentCost {
63	  source: "measured" | "estimated_chars" | "tool_count_fallback";
64	}
65	
66	export interface CostEstimateResultWithSource {
67	  perAgent: AgentCostWithSource[];
68	  totalUsd: number;
69	  source: "measured" | "estimated_chars" | "tool_count_fallback";
70	}
71	
72	/**
73	 * Estimate USD cost per agent.
74	 *
75	 * When tokensMap is provided (from transcript), uses those as measured values.
76	 * Otherwise reads token counts from events if present (fields: input_tokens, output_tokens, model).
77	 */
78	export function costEstimate(
79	  state: State,
80	  tokensMap?: Record<string, { input_tokens: number; output_tokens: number; cache_read: number; cache_creation: number }>
81	): CostEstimateResultWithSource {
82	  const perAgent: AgentCostWithSource[] = [];
83	  let totalUsd = 0;
84	  const hasMeasured = tokensMap != null;
85	
86	  for (const agent of state.agents.values()) {
87	    let inputTokens = 0;
88	    let outputTokens = 0;
89	    let model: "sonnet" | "opus" = "sonnet";
90	    let source: "measured" | "estimated_chars" | "tool_count_fallback" = "tool_count_fallback";
91	
92	    if (hasMeasured && tokensMap[agent.id] != null) {
93	      // Use transcript-measured tokens
94	      inputTokens = tokensMap[agent.id]!.input_tokens;
95	      outputTokens = tokensMap[agent.id]!.output_tokens;
96	      if (inputTokens > 0 || outputTokens > 0) source = "measured";
97	    }
98	
99	    if (source === "tool_count_fallback") {
100	      // Aggregate token data from events belonging to this agent
101	      for (const event of state.events) {
102	        if (event.agent_id !== agent.id) continue;
103	        const it = event["input_tokens"];
104	        const ot = event["output_tokens"];
105	        const m = event["model"];
106	        if (typeof it === "number") inputTokens += it;
107	        if (typeof ot === "number") outputTokens += ot;
108	        if (typeof m === "string" && m.toLowerCase().includes("opus")) {
109	          model = "opus";
110	        }
111	      }
112	    }
113	
114	    // Char-based fallback: sum chars from tool_calls when no token data found
115	    if (source === "tool_count_fallback" && inputTokens === 0 && outputTokens === 0) {
116	      const calls: ToolCall[] = state.tool_calls.get(agent.id) ?? [];
117	      let inputChars = 0;
118	      let outputChars = 0;
119	      for (const tc of calls) {
120	        inputChars += JSON.stringify(tc.input).length;
121	        outputChars += tc.response?.length ?? 0;
122	      }
123	      if (inputChars > 0 || outputChars > 0) {
124	        // tokens ≈ chars / 4
125	        inputTokens = Math.round(inputChars / 4);
126	        outputTokens = Math.round(outputChars / 4);
127	        source = "estimated_chars";
128	      }
129	    }
130	
131	    const inputRate = model === "opus" ? OPUS_INPUT : SONNET_INPUT;
132	    const outputRate = model === "opus" ? OPUS_OUTPUT : SONNET_OUTPUT;
133	    const usd =
134	      (inputTokens / 1_000_000) * inputRate +
135	      (outputTokens / 1_000_000) * outputRate;
136	
137	    totalUsd += usd;
138	    perAgent.push({
139	      agentId: agent.id,
140	      agentName: agent.name,
141	      inputTokens,
142	      outputTokens,
143	      usd: Math.round(usd * 1_000_000) / 1_000_000,
144	      model,
145	      source,
146	    });
147	  }
148	
149	  const anyMeasured = perAgent.some((a) => a.source === "measured");
150	  const anyCharEstimated = perAgent.some((a) => a.source === "estimated_chars");
151	
152	  return {
153	    perAgent,
154	    totalUsd: Math.round(totalUsd * 1_000_000) / 1_000_000,
155	    source: anyMeasured ? "measured" : anyCharEstimated ? "estimated_chars" : "tool_count_fallback",
156	  };
157	}
158	
159	// ── Parallelism gaps ──────────────────────────────────────────────────────
160	
161	export interface ParallelismGap {
162	  agents: [string, string]; // agent IDs that ran sequentially but had no dependency
163	  aEndMs: number;
164	  bStartMs: number;
165	  overlapOpportunityMs: number;
166	}
167	
168	/**
169	 * Find agents that ran sequentially but share no data dependency
170	 * (no parent-child edge between them and their time ranges don't overlap).
171	 *
172	 * Heuristic: two sibling agents (same parent) where one ended before the
173	 * other started — they could potentially have been parallelised.
174	 */
175	export function parallelismGaps(state: State): ParallelismGap[] {
176	  const gaps: ParallelismGap[] = [];
177	
178	  // Group agents by parent
179	  const byParent = new Map<string, Agent[]>();
180	  for (const agent of state.agents.values()) {
181	    if (!agent.parent_id) continue;
182	    const siblings = byParent.get(agent.parent_id) ?? [];
183	    siblings.push(agent);
184	    byParent.set(agent.parent_id, siblings);
185	  }
186	
187	  // Build edge set for dependency check
188	  const edgePairs = new Set<string>(
189	    state.edges.map((e) => `${e.from_id}|${e.to_id}`)
190	  );
191	
192	  for (const siblings of byParent.values()) {
193	    if (siblings.length < 2) continue;
194	
195	    // Sort by start time
196	    const sorted = [...siblings].sort((a, b) => a.first_seen_ms - b.first_seen_ms);
197	
198	    for (let i = 0; i < sorted.length - 1; i++) {
199	      for (let j = i + 1; j < sorted.length; j++) {
200	        const a = sorted[i]!;
201	        const b = sorted[j]!;
202	
203	        // Skip if there's a direct dependency edge between them
204	        const hasDep =
205	          edgePairs.has(`${a.id}|${b.id}`) || edgePairs.has(`${b.id}|${a.id}`);
206	        if (hasDep) continue;
207	
208	        // Check sequential: a ended before b started
209	        if (a.last_seen_ms > 0 && b.first_seen_ms > a.last_seen_ms) {
210	          const gap = b.first_seen_ms - a.last_seen_ms;
211	          gaps.push({
212	            agents: [a.id, b.id],
213	            aEndMs: a.last_seen_ms,
214	            bStartMs: b.first_seen_ms,
215	            overlapOpportunityMs: gap,
216	          });
217	        }
218	      }
219	    }
220	  }
221	
222	  // Sort by largest opportunity first
223	  return gaps.sort((a, b) => b.overlapOpportunityMs - a.overlapOpportunityMs);
224	}
225	
226	// ── Stuck signals ─────────────────────────────────────────────────────────
227	
228	export interface StuckSignal {
229	  agentId: string;
230	  agentName: string;
231	  reason: "repeated_tool" | "consecutive_failures";
232	  detail: string;
233	  tool_name?: string;
234	  count: number;
235	}
236	
237	const REPEAT_WINDOW_MS = 60_000; // 1 minute
238	const REPEAT_THRESHOLD = 3;
239	const CONSECUTIVE_FAILURE_THRESHOLD = 3;
240	
241	function hashInput(input: Record<string, unknown>): string {
242	  return createHash("sha1").update(JSON.stringify(input)).digest("hex").slice(0, 8);
243	}
244	
245	/**
246	 * Detect agents that are stuck:
247	 *   1. Repeated tool calls: same tool_name + same input hash, N times within window
248	 *   2. Consecutive failures: N consecutive PostToolUseFailure events
249	 */
250	export function stuckSignals(state: State): StuckSignal[] {
251	  const signals: StuckSignal[] = [];
252	
253	  for (const agent of state.agents.values()) {
254	    // Skip already-done agents
255	    if (agent.status === "done") continue;
256	
257	    const calls: ToolCall[] = state.tool_calls.get(agent.id) ?? [];
258	
259	    // --- Repeated tool calls ---
260	    // Group by (tool_name, input_hash) within window
261	    const buckets = new Map<string, { count: number; firstMs: number; lastMs: number }>();
262	    for (const tc of calls) {
263	      const key = `${tc.tool_name}|${hashInput(tc.input)}`;
264	      const bucket = buckets.get(key);
265	      if (!bucket) {
266	        buckets.set(key, { count: 1, firstMs: tc.started_ms, lastMs: tc.started_ms });
267	      } else {
268	        bucket.count++;
269	        bucket.lastMs = tc.started_ms;
270	      }
271	    }
272	    for (const [key, bucket] of buckets) {
273	      if (
274	        bucket.count >= REPEAT_THRESHOLD &&
275	        bucket.lastMs - bucket.firstMs <= REPEAT_WINDOW_MS
276	      ) {
277	        const [toolName] = key.split("|");
278	        signals.push({
279	          agentId: agent.id,
280	          agentName: agent.name,
281	          reason: "repeated_tool",
282	          detail: `Tool "${toolName}" called ${bucket.count} times with same input within ${REPEAT_WINDOW_MS / 1000}s`,
283	          tool_name: toolName,
284	          count: bucket.count,
285	        });
286	      }
287	    }
288	
289	    // --- Consecutive failures ---
290	    // Count trailing consecutive error tool calls
291	    let consecutiveErrors = 0;
292	    for (let i = calls.length - 1; i >= 0; i--) {
293	      const tc = calls[i]!;
294	      if (tc.status === "error") {
295	        consecutiveErrors++;
296	      } else {
297	        break;
298	      }
299	    }
300	    if (consecutiveErrors >= CONSECUTIVE_FAILURE_THRESHOLD) {
301	      signals.push({
302	        agentId: agent.id,
303	        agentName: agent.name,
304	        reason: "consecutive_failures",
305	        detail: `${consecutiveErrors} consecutive tool failures`,
306	        count: consecutiveErrors,
307	      });
308	    }
309	  }
310	
311	  return signals;
312	}
313	
314	// ── Error recovery ────────────────────────────────────────────────────────
315	
316	export type RecoveryStatus = "retried_succeeded" | "retried_failed" | "no_retry";
317	
318	export interface ErrorRecoveryEntry {
319	  agentId: string;
320	  agentName: string;
321	  tool_name: string;
322	  failed_tool_id: string;
323	  recovery: RecoveryStatus;
324	  retry_tool_id: string | null;
325	}
326	
327	const RETRY_WINDOW_MS = 60_000;
328	
329	/**
330	 * Scan tool calls for failed ones, then check if the same agent retried with
331	 * the same tool_name within 60s. Classify recovery.
332	 */
333	export function errorRecovery(state: State): ErrorRecoveryEntry[] {
334	  const entries: ErrorRecoveryEntry[] = [];
335	
336	  for (const agent of state.agents.values()) {
337	    const calls: ToolCall[] = state.tool_calls.get(agent.id) ?? [];
338	
339	    for (let i = 0; i < calls.length; i++) {
340	      const tc = calls[i]!;
341	      if (tc.status !== "error") continue;
342	
343	      // Look for a retry: same tool_name within RETRY_WINDOW_MS, after the failure
344	      let recovery: RecoveryStatus = "no_retry";
345	      let retry_tool_id: string | null = null;
346	
347	      for (let j = i + 1; j < calls.length; j++) {
348	        const candidate = calls[j]!;
349	        if (candidate.started_ms - tc.started_ms > RETRY_WINDOW_MS) break;
350	        if (candidate.tool_name !== tc.tool_name) continue;
351	        // Found a retry
352	        retry_tool_id = candidate.id;
353	        recovery = candidate.status === "done" ? "retried_succeeded" : "retried_failed";
354	        break;
355	      }
356	
357	      entries.push({
358	        agentId: agent.id,
359	        agentName: agent.name,
360	        tool_name: tc.tool_name,
361	        failed_tool_id: tc.id,
362	        recovery,
363	        retry_tool_id,
364	      });
365	    }
366	  }
367	
368	  return entries;
369	}
370	
371	// ── Agent performance table ───────────────────────────────────────────────
372	
373	export interface AgentPerfRow {
374	  id: string;
375	  name: string;
376	  type: string | null;
377	  duration_ms: number;
378	  tool_count: number;
379	  errors: number;
380	  cost_usd: number;
381	}
382	
383	/**
384	 * Build a per-agent performance table using computed cost from costEstimate.
385	 */
386	export function agentPerformanceTable(
387	  state: State,
388	  cost: CostEstimateResultWithSource
389	): AgentPerfRow[] {
390	  const costById = new Map(cost.perAgent.map((a) => [a.agentId, a.usd]));
391	
392	  return Array.from(state.agents.values()).map((agent) => ({
393	    id: agent.id,
394	    name: agent.name,
395	    type: agent.subagent_type,
396	    duration_ms: agent.last_seen_ms - agent.first_seen_ms,
397	    tool_count: agent.tool_count,
398	    errors: agent.error_count,
399	    cost_usd: costById.get(agent.id) ?? 0,
400	  }));
401	}
402	
403	// ── Agent type profiles ───────────────────────────────────────────────────
404	
405	export interface AgentTypeProfile {
406	  type: string;
407	  sample_count: number;
408	  avg_duration_ms: number;
409	  avg_tool_count: number;
410	  summary: string;
411	}
412	
413	/**
414	 * Group agents by subagent_type and produce plain-English profiles.
415	 */
416	export function agentTypeProfiles(state: State): AgentTypeProfile[] {
417	  const groups = new Map<string, { durations: number[]; toolCounts: number[] }>();
418	
419	  for (const agent of state.agents.values()) {
420	    const type = agent.subagent_type ?? "root";
421	    const g = groups.get(type) ?? { durations: [], toolCounts: [] };
422	    g.durations.push(agent.last_seen_ms - agent.first_seen_ms);
423	    g.toolCounts.push(agent.tool_count);
424	    groups.set(type, g);
425	  }
426	
427	  const profiles: AgentTypeProfile[] = [];
428	
429	  for (const [type, g] of groups) {
430	    const n = g.durations.length;
431	    const avg_duration_ms = Math.round(g.durations.reduce((a, b) => a + b, 0) / n);
432	    const avg_tool_count = Math.round(g.toolCounts.reduce((a, b) => a + b, 0) / n);
433	
434	    // Build plain-English ranges
435	    const minTools = Math.min(...g.toolCounts);
436	    const maxTools = Math.max(...g.toolCounts);
437	    const minDurS = (Math.min(...g.durations) / 1000).toFixed(1);
438	    const maxDurS = (Math.max(...g.durations) / 1000).toFixed(1);
439	
440	    const toolRange = minTools === maxTools ? `${minTools}` : `${minTools}-${maxTools}`;
441	    const durRange =
442	      minDurS === maxDurS ? `${minDurS}s` : `${minDurS}s-${maxDurS}s`;
443	
444	    const summary =
445	      `Usually makes ${toolRange} tool call${maxTools !== 1 ? "s" : ""}, ` +
446	      `takes ${durRange} ` +
447	      `(${n} sample${n !== 1 ? "s" : ""})`;
448	
449	    profiles.push({ type, sample_count: n, avg_duration_ms, avg_tool_count, summary });
450	  }
451	
452	  return profiles.sort((a, b) => b.sample_count - a.sample_count);
453	}
454	
455	// ── Agent type trends (from baselines) ────────────────────────────────────
456	
457	export interface BaselineRow {
458	  agent_type: string;
459	  mean_duration: number;
460	  mean_tool_count: number;
461	  mean_cost: number;
462	  sample_count: number;
463	  stddev_duration: number;
464	  stddev_tool_count: number;
465	  updated_at: number;
466	  tool_sequence_common?: string;
467	}
468	
469	export interface AgentTypeTrend {
470	  type: string;
471	  sample_count: number;
472	  summary: string;
473	}
474	
475	/**
476	 * Produce per-type plain-English summary from stored baselines.
477	 * Uses mean ± stddev to compute human-readable ranges.
478	 */
479	export function agentTypeTrends(baselines: BaselineRow[]): AgentTypeTrend[] {
480	  return baselines.map((b) => {
481	    const toolLow = Math.max(0, Math.round(b.mean_tool_count - b.stddev_tool_count));
482	    const toolHigh = Math.round(b.mean_tool_count + b.stddev_tool_count);
483	    const durLowS = Math.max(0, (b.mean_duration - b.stddev_duration) / 1000);
484	    const durHighS = (b.mean_duration + b.stddev_duration) / 1000;
485	
486	    const toolRange =
487	      toolLow === toolHigh
488	        ? `${toolLow}`
489	        : `${toolLow}-${toolHigh}`;
490	
491	    const durRange =
492	      Math.abs(durHighS - durLowS) < 0.05
493	        ? `${durLowS.toFixed(1)}s`
494	        : `${durLowS.toFixed(1)}-${durHighS.toFixed(1)}s`;
495	
496	    const summary =
497	      `Usually makes ${toolRange} tool call${toolHigh !== 1 ? "s" : ""}, ` +
498	      `takes ${durRange} based on ${b.sample_count} prior run${b.sample_count !== 1 ? "s" : ""}`;
499	
500	    return { type: b.agent_type, sample_count: b.sample_count, summary };
501	  });
502	}
503	
504	// ── Budget exceeded detection ─────────────────────────────────────────────
505	
506	export interface BudgetExceeded {
507	  session_id: string;
508	  current: number;
509	  budget: number;
510	  kill: boolean;
511	}
512	
513	/**
514	 * For each session with a budget set, compute its cumulative cost; if
515	 * cost > budget, emit a BudgetExceeded record. Caller is responsible for
516	 * deduping (only emit on the first crossing).
517	 */
518	export function detectBudgetExceeded(state: State): BudgetExceeded[] {
519	  const out: BudgetExceeded[] = [];
520	  if (state.sessions.size === 0) return out;
521	
522	  // Compute per-session cost from per-agent cost
523	  const cost = costEstimate(state);
524	  const costPerSession = new Map<string, number>();
525	  for (const a of cost.perAgent) {
526	    const agent = state.agents.get(a.agentId);
527	    if (!agent) continue;
528	    const sid = agent.session_id;
529	    costPerSession.set(sid, (costPerSession.get(sid) ?? 0) + a.usd);
530	  }
531	
532	  for (const [sid, session] of state.sessions) {
533	    if (typeof session.budget_usd !== "number" || session.budget_usd <= 0) continue;
534	    const current = costPerSession.get(sid) ?? 0;
535	    if (current > session.budget_usd) {
536	      out.push({
537	        session_id: sid,
538	        current: Math.round(current * 1_000_000) / 1_000_000,
539	        budget: session.budget_usd,
540	        kill: session.kill_on_exceed === true,
541	      });
542	    }
543	  }
544	  return out;
545	}
546	
547	// ── Z-score badge ─────────────────────────────────────────────────────────
548	
549	export type ZScoreBadge = "fast" | "normal" | "slow";
550	
551	/**
552	 * Compute z-score of agent duration vs baseline. Returns null if
553	 * baseline has insufficient samples or zero stddev.
554	 */
555	export function zScoreBadge(
556	  agentDurationMs: number,
557	  baseline: BaselineRow
558	): ZScoreBadge | null {
559	  if (baseline.sample_count < 5 || baseline.stddev_duration === 0) return null;
560	  const z = (agentDurationMs - baseline.mean_duration) / baseline.stddev_duration;
561	  if (z < -1) return "fast";
562	  if (z > 1) return "slow";
563	  return "normal";
564	}
